if (! function_exists('chart_pie')) {
    function chart_pie($labels, $values, $title = null, $width = null, $height = null, $donut_hole = null, $colors = null, $show_percentages = null, $show_legend = null, $filename = null, $bg_color = null, $explode = null, $label_font_size = null)
    {
        $labels = $labels ?? [];
        $values = $values ?? [];
        $width = (int)($width ?? 700);
        $height = (int)($height ?? 500);
        $donut_hole = (float)($donut_hole ?? 0.35);
        $show_percentages = $show_percentages ?? true;
        $show_legend = $show_legend ?? true;
        $title = $title ?? '';
        $bg_color_str = $bg_color ?? '#FFFFFF';
        $explode = $explode ?? [];
        $label_font_size = (int)($label_font_size ?? 5);
        if ($label_font_size < 1) $label_font_size = 1;
        if ($label_font_size > 5) $label_font_size = 5;

        // Validate inputs
        $n = count($labels);
        if ($n === 0 || count($values) === 0) {
            return ['success' => false, 'error' => 'Labels and values arrays must not be empty.'];
        }
        if ($n !== count($values)) {
            return ['success' => false, 'error' => 'Labels and values arrays must have the same length.'];
        }
        if ($width < 300 || $width > 2000) {
            return ['success' => false, 'error' => 'Width must be between 300 and 2000.'];
        }
        if ($height < 300 || $height > 1500) {
            return ['success' => false, 'error' => 'Height must be between 300 and 1500.'];
        }
        if ($donut_hole < 0.0 || $donut_hole > 0.85) {
            return ['success' => false, 'error' => 'Donut hole must be between 0.0 and 0.85.'];
        }

        // Ensure all values are positive
        $total = 0;
        $cleaned_values = [];
        foreach ($values as $i => $v) {
            $v = (float)$v;
            if ($v < 0) $v = 0;
            $cleaned_values[$i] = $v;
            $total += $v;
        }
        $values = $cleaned_values;

        if ($total <= 0) {
            return ['success' => false, 'error' => 'Sum of values must be greater than zero.'];
        }

        // Parse hex to RGB
        $hex_to_rgb = function($hex) {
            $hex = ltrim($hex, '#');
            if (strlen($hex) === 3) {
                $hex = $hex[0].$hex[0].$hex[1].$hex[1].$hex[2].$hex[2];
            }
            if (strlen($hex) < 6) {
                $hex = str_pad($hex, 6, '0');
            }
            return [
                hexdec(substr($hex, 0, 2)),
                hexdec(substr($hex, 2, 2)),
                hexdec(substr($hex, 4, 2)),
            ];
        };

        // Build color palette
        $default_palette = [
            '#FF6384', '#36A2EB', '#FFCE56', '#4BC0C0', '#9966FF',
            '#FF9F40', '#C9CBCF', '#7BC043', '#F37735', '#B10DC9',
            '#17BECF', '#E377C2', '#8C564B', '#D62728', '#9467BD',
            '#EF553B', '#00CC96', '#AB63FA', '#FFA15A', '#19D3F3',
        ];

        $override_colors = $colors ?? [];
        $valid_override = is_array($override_colors) && count($override_colors) > 0;

        $slice_colors = [];
        for ($i = 0; $i < $n; $i++) {
            if ($valid_override) {
                $slice_colors[$i] = $override_colors[$i % count($override_colors)];
            } else {
                $slice_colors[$i] = $default_palette[$i % count($default_palette)];
            }
        }

        // Parse background
        $bg_rgb = $hex_to_rgb($bg_color_str);

        // Create image
        $img = imagecreatetruecolor($width, $height);
        $bg_color_idx = imagecolorallocate($img, $bg_rgb[0], $bg_rgb[1], $bg_rgb[2]);
        imagefill($img, 0, 0, $bg_color_idx);
        imageantialias($img, true);

        // Calculate layout
        $legend_width = $show_legend ? (int)($width * 0.28) : 0;
        $title_height = (!empty($title)) ? 45 : 10;
        $chart_area_width = $width - $legend_width - 60;
        $chart_area_height = $height - $title_height - 40;
        $pie_cx = (int)(30 + $chart_area_width / 2);
        $pie_cy = (int)($title_height + $chart_area_height / 2);
        $pie_diameter = min($chart_area_width, $chart_area_height) - 20;
        $pie_radius = (int)($pie_diameter / 2);

        // Colors
        $text_color = imagecolorallocate($img, 60, 60, 60);
        $gray = imagecolorallocate($img, 140, 140, 140);
        $border_color = imagecolorallocate($img, 80, 80, 80);

        // Draw title with built-in font (no TTF dependency)
        if (!empty($title)) {
            $title_width = strlen($title) * imagefontwidth(5);
            $title_x = (int)($pie_cx - $title_width / 2);
            imagestring($img, 5, $title_x, 10, $title, $text_color);
        }

        // Allocate slice colors
        $allocated = [];
        $dark = [];
        foreach ($slice_colors as $i => $hex) {
            $rgb = $hex_to_rgb($hex);
            $allocated[$i] = imagecolorallocate($img, $rgb[0], $rgb[1], $rgb[2]);
            $dark[$i] = imagecolorallocate($img, max(0, $rgb[0]-50), max(0, $rgb[1]-50), max(0, $rgb[2]-50));
        }

        // Compute percentages
        $percentages = [];
        foreach ($values as $i => $v) {
            $percentages[$i] = ($v / $total) * 100;
        }

        // Draw slices
        $start_angle = -90;
        $mid_angles = []; // Store mid-angle for label positioning

        foreach ($values as $i => $v) {
            $arc_angle = ($v / $total) * 360;
            $mid_angle = $start_angle + $arc_angle / 2;
            $mid_angles[$i] = $mid_angle;
            
            // Explode offset
            $ex_dx = 0;
            $ex_dy = 0;
            if (in_array($i, $explode)) {
                $rad = deg2rad($mid_angle);
                $offset = (int)($pie_radius * 0.08);
                $ex_dx = (int)(cos($rad) * $offset);
                $ex_dy = (int)(sin($rad) * $offset);
            }
            
            // Filled slice
            imagefilledarc($img, $pie_cx + $ex_dx, $pie_cy + $ex_dy,
                $pie_diameter, $pie_diameter,
                (int)$start_angle, (int)($start_angle + $arc_angle),
                $allocated[$i], IMG_ARC_PIE);
            
            // Edge
            imagefilledarc($img, $pie_cx + $ex_dx, $pie_cy + $ex_dy,
                $pie_diameter, $pie_diameter,
                (int)$start_angle, (int)($start_angle + $arc_angle),
                $dark[$i], IMG_ARC_EDGED | IMG_ARC_NOFILL);
            
            $start_angle += $arc_angle;
        }

        // Donut hole
        if ($donut_hole > 0) {
            $hole_diameter = (int)($pie_diameter * $donut_hole);
            imagefilledarc($img, $pie_cx, $pie_cy,
                $hole_diameter, $hole_diameter,
                0, 360, $bg_color_idx, IMG_ARC_PIE);
            imagefilledarc($img, $pie_cx, $pie_cy,
                $hole_diameter, $hole_diameter,
                0, 360, $gray, IMG_ARC_EDGED | IMG_ARC_NOFILL);
            
            // Total in center
            $total_text = number_format($total);
            $tx = (int)($pie_cx - strlen($total_text) * imagefontwidth(3) / 2);
            imagestring($img, 3, $tx, (int)($pie_cy - imagefontheight(3)/2), $total_text, $text_color);
        }

        // Percentage labels on slices
        if ($show_percentages) {
            foreach ($values as $i => $v) {
                $pct = $percentages[$i];
                if ($pct < 4) continue;
                
                $mid = $mid_angles[$i];
                $rad = deg2rad($mid);
                
                $explode_offset = in_array($i, $explode) ? (int)($pie_radius * 0.08) : 0;
                
                $label_r = $donut_hole > 0
                    ? ($pie_radius * (1 + $donut_hole) / 2)
                    : ($pie_radius * 0.65);
                
                $lx = (int)($pie_cx + cos($rad) * ($label_r + $explode_offset));
                $ly = (int)($pie_cy + sin($rad) * ($label_r + $explode_offset));
                
                $pct_text = round($pct, 1) . '%';
                $tw = strlen($pct_text) * imagefontwidth($label_font_size);
                $th = imagefontheight($label_font_size);
                
                // Shadow then text
                imagestring($img, $label_font_size, (int)($lx - $tw/2 + 1), (int)($ly - $th/2 + 1), $pct_text, $bg_color_idx);
                imagestring($img, $label_font_size, (int)($lx - $tw/2), (int)($ly - $th/2), $pct_text, $text_color);
            }
        }

        // Legend
        if ($show_legend) {
            $lx_start = $width - $legend_width + 20;
            $ly = $title_height + 15;
            $item_h = 22;
            
            // Legend border
            $legend_h = min($n * $item_h + 15, $height - $title_height - 25);
            imagerectangle($img, $lx_start - 5, $ly - 5,
                $lx_start + ($legend_width - 30), $ly + $legend_h,
                $gray);
            
            foreach ($labels as $i => $label) {
                if ($ly + $item_h > $height - 20) break;
                
                // Color swatch
                imagefilledrectangle($img, $lx_start, $ly, $lx_start + 14, $ly + 10, $allocated[$i]);
                imagerectangle($img, $lx_start, $ly, $lx_start + 14, $ly + 10, $dark[$i]);
                
                // Label text
                $label_text = $label . ' (' . round($percentages[$i], 1) . '%)';
                if (strlen($label_text) > 24) {
                    $label_text = substr($label, 0, 16) . '.. (' . round($percentages[$i], 1) . '%)';
                }
                imagestring($img, 3, $lx_start + 20, $ly - 1, $label_text, $text_color);
                
                $ly += $item_h;
            }
        }

        // Save
        $workspace = __DIR__ . '/../workspace';
        if (!is_dir($workspace)) {
            mkdir($workspace, 0755, true);
        }

        $filename = $filename ?? ('pie_chart_' . date('Ymd_His'));
        if (!str_ends_with(strtolower($filename), '.png')) {
            $filename .= '.png';
        }
        $filepath = $workspace . '/' . $filename;

        $saved = imagepng($img, $filepath, 6);
        imagedestroy($img);

        if (!$saved) {
            return ['success' => false, 'error' => 'Failed to save PNG file to: ' . $filepath];
        }

        return [
            'success' => true,
            'filepath' => $filepath,
            'filename' => basename($filepath),
            'dimensions' => ['width' => $width, 'height' => $height],
            'donut' => $donut_hole > 0,
            'donut_hole_fraction' => $donut_hole,
            'slices' => $n,
            'total' => $total,
            'data' => array_map(function($i) use ($labels, $values, $percentages, $slice_colors) {
                return [
                    'label' => $labels[$i],
                    'value' => $values[$i],
                    'percentage' => round($percentages[$i], 2),
                    'color' => $slice_colors[$i],
                ];
            }, array_keys($labels)),
            'exploded_slices' => $explode,
        ];
    }
